import React, { useState } from 'react';
import Layout from './Layout';
import { useAuth } from '../context/AuthContext';
import { Card, CardHeader, CardTitle, CardContent } from './ui/card';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Select } from './ui/select';
import { Alert, AlertDescription } from './ui/alert';
import { Upload } from 'lucide-react';

const ClienteForm = () => {
  const { user } = useAuth();
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    nombre: '',
    nombreComercial: '',
    direccion: '',
    poblacion: '',
    codigoPostal: '',
    nombreContacto: '',
    telefono: '',
    correo: '',
    web: '',
    cifNif: '',
    tipoCarga: '',
    sepaDocumento: null,
    
    // Datos del director comercial
    condicionesEnvio: '',
    condicionesEntrega: '',
    requierePlataforma: false,
    tipoEnvio: '',
    horario: '',
    tipoDescarga: ''
  });

  const [errors, setErrors] = useState({});

  const validateComercialForm = () => {
    const newErrors = {};
    const requiredFields = [
      'nombre', 'direccion', 'poblacion', 'codigoPostal',
      'nombreContacto', 'telefono', 'correo', 'cifNif', 'tipoCarga'
    ];

    requiredFields.forEach(field => {
      if (!formData[field]) {
        newErrors[field] = 'Este campo es obligatorio';
      }
    });

    if (!formData.sepaDocumento) {
      newErrors.sepaDocumento = 'Debe adjuntar el documento SEPA';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
    // Limpiar error del campo cuando se modifica
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: null
      }));
    }
  };

  const handleSubmit = async () => {
    if (!validateComercialForm()) {
      return;
    }
    setCurrentStep(prev => prev + 1);
  };

  return (
    <Layout>
      <div className="container mx-auto px-4 py-8">
        <Card className="max-w-4xl mx-auto">
          <CardHeader>
            <CardTitle className="text-2xl font-bold">
              Sistema de Alta de Nuevos Clientes
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="mb-8">
              <div className="flex justify-between items-center mb-8">
                {[1, 2, 3, 4].map((step) => (
                  <div
                    key={step}
                    className={`w-12 h-12 rounded-full flex items-center justify-center ${
                      currentStep === step
                        ? 'bg-blue-600 text-white'
                        : 'bg-gray-200 text-gray-600'
                    }`}
                  >
                    {step}
                  </div>
                ))}
              </div>
              <h2 className="text-xl font-semibold mb-4">
                Alta de Nuevo Cliente - Paso {currentStep} de 4
              </h2>
            </div>

            {currentStep === 1 && (
              <form className="space-y-6" onSubmit={e => e.preventDefault()}>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="nombre">Nombre Empresa *</Label>
                    <Input
                      id="nombre"
                      value={formData.nombre}
                      onChange={(e) => handleChange('nombre', e.target.value)}
                      className={errors.nombre ? 'border-red-500' : ''}
                    />
                    {errors.nombre && (
                      <span className="text-sm text-red-500">{errors.nombre}</span>
                    )}
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="tipoCarga">Tipo de Carga *</Label>
                    <Select 
                      id="tipoCarga"
                      value={formData.tipoCarga}
                      onChange={(e) => handleChange('tipoCarga', e.target.value)}
                    >
                      <option value="">Seleccione tipo de carga</option>
                      <option value="COMP">COMP</option>
                      <option value="CROSS">CROSS</option>
                      <option value="GRUP">GRUP</option>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="direccion">Dirección *</Label>
                    <Input
                      id="direccion"
                      value={formData.direccion}
                      onChange={(e) => handleChange('direccion', e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="poblacion">Población *</Label>
                    <Input
                      id="poblacion"
                      value={formData.poblacion}
                      onChange={(e) => handleChange('poblacion', e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="codigoPostal">Código Postal *</Label>
                    <Input
                      id="codigoPostal"
                      value={formData.codigoPostal}
                      onChange={(e) => handleChange('codigoPostal', e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="nombreContacto">Nombre Contacto *</Label>
                    <Input
                      id="nombreContacto"
                      value={formData.nombreContacto}
                      onChange={(e) => handleChange('nombreContacto', e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="telefono">Teléfono *</Label>
                    <Input
                      id="telefono"
                      value={formData.telefono}
                      onChange={(e) => handleChange('telefono', e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="correo">Correo Electrónico *</Label>
                    <Input
                      id="correo"
                      type="email"
                      value={formData.correo}
                      onChange={(e) => handleChange('correo', e.target.value)}
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="cifNif">CIF/NIF *</Label>
                    <Input
                      id="cifNif"
                      value={formData.cifNif}
                      onChange={(e) => handleChange('cifNif', e.target.value)}
                    />
                  </div>
                </div>

                <div className="mt-6">
                  <Label>Documento SEPA *</Label>
                  <div className="mt-2">
                    <Button
                      type="button"
                      variant="outline"
                      onClick={() => document.getElementById('sepa-upload').click()}
                    >
                      <Upload className="mr-2 h-4 w-4" />
                      Subir documento SEPA
                    </Button>
                    <input
                      id="sepa-upload"
                      type="file"
                      className="hidden"
                      onChange={(e) => handleChange('sepaDocumento', e.target.files[0])}
                    />
                    {formData.sepaDocumento && (
                      <p className="mt-2 text-sm text-gray-600">
                        Archivo seleccionado: {formData.sepaDocumento.name}
                      </p>
                    )}
                  </div>
                </div>

                <div className="flex justify-end mt-8">
                  <Button onClick={handleSubmit}>
                    Siguiente
                  </Button>
                </div>
              </form>
            )}

            {currentStep === 2 && (
              <Alert>
                <AlertDescription>
                  Esperando validación del Director Comercial
                </AlertDescription>
              </Alert>
            )}
          </CardContent>
        </Card>
      </div>
    </Layout>
  );
};

export default ClienteForm;
